// ContainerServiceServer is the server API for ContainerService service.
// All implementations must embed UnimplementedContainerServiceServer
// for forward compatibility.
//
// ContainerService provides container management operations
type ContainerServiceServer interface {
	// CreateContainer creates a new container for a user
	CreateContainer(context.Context, *CreateContainerRequest) (*CreateContainerResponse, error)
	// ListContainers lists all containers with optional filtering
	ListContainers(context.Context, *ListContainersRequest) (*ListContainersResponse, error)
	// GetContainer gets detailed information about a specific container
	GetContainer(context.Context, *GetContainerRequest) (*GetContainerResponse, error)
	// DebugContainer reports diagnostic information about a container's
	// SSH path: state, host user, shell, recent sshd rejections.
	DebugContainer(context.Context, *DebugContainerRequest) (*DebugContainerResponse, error)
	// DeleteContainer deletes a container
	DeleteContainer(context.Context, *DeleteContainerRequest) (*DeleteContainerResponse, error)
	// StartContainer starts a stopped container
	StartContainer(context.Context, *StartContainerRequest) (*StartContainerResponse, error)
	// StopContainer stops a running container
	StopContainer(context.Context, *StopContainerRequest) (*StopContainerResponse, error)
	// ResizeContainer dynamically adjusts container resources
	ResizeContainer(context.Context, *ResizeContainerRequest) (*ResizeContainerResponse, error)
	// MoveContainer migrates a container from the local daemon (source)
	// to a peer daemon (target) using pre-copy snapshot + delta refresh.
	// Three phases: (1) initial snapshot copy while source keeps running,
	// (2) iterative delta refreshes to shrink the dirty set, (3) brief
	// stop + final delta + start-on-target + route swap. Downtime is
	// sub-second on quiet workloads with ZFS/btrfs storage; minutes
	// for active workloads on dir-pool. Prereq: incus remotes
	// configured both ways between the source and target VMs.
	MoveContainer(context.Context, *MoveContainerRequest) (*MoveContainerResponse, error)
	// AdoptMigratedContainer is the destination-side helper RPC called by
	// a peer's MoveContainer after `incus copy` has pushed the LXC to
	// this daemon. It registers the container with this daemon's state
	// (host user, route record at the new IP) so the LXC is fully
	// operational under Containarium's API surface, then returns the
	// container's new local IP for the caller to wire into the route
	// store cutover. Internal use only — operators don't call this.
	AdoptMigratedContainer(context.Context, *AdoptMigratedContainerRequest) (*AdoptMigratedContainerResponse, error)
	// ToggleMonitoring enables or disables application-emitted OTel
	// on an existing container without recreate. When enabling, the
	// daemon stamps OTEL_EXPORTER_OTLP_ENDPOINT and related env vars
	// pointing at this VM's core OTel collector LXC, then restarts
	// the container so the new env reaches the app process. When
	// disabling, the four OTEL_* env vars are unset and the container
	// is restarted so the SDK falls back to its built-in "no endpoint,
	// buffer + drop" behavior. Requires the daemon to be wired with
	// a collector endpoint (--otel-collector-endpoint or auto-ensured
	// core collector); without one, enabling fails with
	// FAILED_PRECONDITION rather than silently writing dead env vars.
	ToggleMonitoring(context.Context, *ToggleMonitoringRequest) (*ToggleMonitoringResponse, error)
	// ToggleAutoSleep opts a container into manual auto-sleep tracking
	// (Phase 1 of the serverless feature). Writes the per-container
	// Incus user.* metadata keys; does NOT itself sleep or wake the
	// container. The Phase 2 ticker (auto-sleep daemon) and Phase 3
	// HTTP wake proxy are separate work — this RPC only sets the flag
	// they will consume.
	ToggleAutoSleep(context.Context, *ToggleAutoSleepRequest) (*ToggleAutoSleepResponse, error)
	// SetContainerTTL schedules or clears a container's auto-delete time.
	// duration_seconds == 0 clears any existing TTL; > 0 sets
	// ttl_expires_at to now() + duration. duration_seconds is capped at
	// 604800 (7 days); larger values return InvalidArgument. Mirrors
	// the 168h ceiling enforced by the `containarium ttl set` CLI
	// (PR #297) — see internal/ttlsweeper for the consumer side.
	//
	// The daemon-side handler is not yet implemented; this scaffold PR
	// adds the proto + sweeper decision logic only. Until the wiring PR
	// lands, calls return Unimplemented and the CLI degrades to a
	// graceful no-op (per PR #297).
	SetContainerTTL(context.Context, *SetContainerTTLRequest) (*SetContainerTTLResponse, error)
	// SetContainerDeletePolicy protects or unprotects a container from the
	// daemon's automated/bulk deletion paths (#284). DELETE_POLICY_PROTECTED
	// makes the ttlsweeper auto-reap and `containarium prune` skip the box;
	// DELETE_POLICY_UNSPECIFIED returns it to the default. A deliberate
	// single-box delete always succeeds regardless. The policy is persisted on
	// the Incus config under user.containarium.delete_policy, so it survives
	// daemon restart with no separate store — read back on list/get.
	SetContainerDeletePolicy(context.Context, *SetContainerDeletePolicyRequest) (*SetContainerDeletePolicyResponse, error)
	// SetContainerAttribution merges labels onto an EXISTING container's config
	// (cloud #746). The hosted control plane stamps attribution labels
	// (cloud_org_id / cloud_container_id / managed_by) at create time today; this
	// endpoint lets it stamp them AFTER the fact, which the cloud's adopt flow
	// (cloud #539) needs to bring a host's pre-existing (orphan) container under
	// org management. Merge semantics: each provided label is set; labels not
	// named are left intact. Cloud→daemon plumbing (like /authorized-keys/sentinel),
	// not a standalone operator action — no CLI verb.
	SetContainerAttribution(context.Context, *SetContainerAttributionRequest) (*SetContainerAttributionResponse, error)
	// AddSSHKey adds an SSH public key to a container
	AddSSHKey(context.Context, *AddSSHKeyRequest) (*AddSSHKeyResponse, error)
	// RemoveSSHKey removes an SSH public key from a container
	RemoveSSHKey(context.Context, *RemoveSSHKeyRequest) (*RemoveSSHKeyResponse, error)
	// AddCollaborator adds a collaborator to a container
	AddCollaborator(context.Context, *AddCollaboratorRequest) (*AddCollaboratorResponse, error)
	// RemoveCollaborator removes a collaborator from a container
	RemoveCollaborator(context.Context, *RemoveCollaboratorRequest) (*RemoveCollaboratorResponse, error)
	// ListCollaborators lists all collaborators for a container
	ListCollaborators(context.Context, *ListCollaboratorsRequest) (*ListCollaboratorsResponse, error)
	// GetMetrics gets runtime metrics for containers
	GetMetrics(context.Context, *GetMetricsRequest) (*GetMetricsResponse, error)
	// CleanupDisk frees disk space inside a container by removing temp files, package caches, and old logs
	CleanupDisk(context.Context, *CleanupDiskRequest) (*CleanupDiskResponse, error)
	// InstallStack installs a software stack or base script on a running container
	InstallStack(context.Context, *InstallStackRequest) (*InstallStackResponse, error)
	// ListStacks returns all available software stacks and their parameter schemas.
	// Used by the web UI to render the Create Container form's stack dropdown
	// and dynamically-shown parameter inputs.
	ListStacks(context.Context, *ListStacksRequest) (*ListStacksResponse, error)
	// GetSystemInfo gets information about the Incus host
	GetSystemInfo(context.Context, *GetSystemInfoRequest) (*GetSystemInfoResponse, error)
	// ListBackends returns the cluster topology — the local daemon plus any
	// tunnel-connected peers — with per-backend health, version, OS, running
	// container count, and GPU inventory. Admin-only: the response discloses
	// fleet topology (peer IDs, hostnames, GPU inventory), which is operator-
	// grade, not tenant-grade. This replaces the former hand-coded
	// /v1/backends HTTP handler with the proto-first, gateway-generated
	// contract (proto-first convention; #354).
	ListBackends(context.Context, *ListBackendsRequest) (*ListBackendsResponse, error)
	// AdvertiseCapacity publishes this backend's spare scheduling headroom to
	// the control plane, bounded by a local policy (time window, excluded
	// workload classes, safety reservation). A box that would scale down can
	// instead offer its freed headroom for control-plane-directed scheduling.
	// The advertisement is surfaced through ListBackends. Admin-only. See #680.
	AdvertiseCapacity(context.Context, *AdvertiseCapacityRequest) (*AdvertiseCapacityResponse, error)
	// WithdrawCapacity withdraws any active headroom advertisement. Idempotent:
	// withdrawing when nothing is advertised succeeds as a no-op. Admin-only.
	// See #680.
	WithdrawCapacity(context.Context, *WithdrawCapacityRequest) (*WithdrawCapacityResponse, error)
	// GetCapacityHeadroom reads this backend's current advertisement and the
	// freshly recomputed spare figures without changing advertise/withdraw
	// state. Admin-only. See #680.
	GetCapacityHeadroom(context.Context, *GetCapacityHeadroomRequest) (*GetCapacityHeadroomResponse, error)
	// ProfileBackend records a backend's hardware capability profile: it reads
	// system info, runs the GPU passthrough probe and a bounded CPU/memory
	// micro-benchmark, derives the measured hardware class, reconciles it
	// against the self-reported class, and persists the profile. The profile is
	// surfaced through ListBackends. Admin-only; runs a short-lived benchmark and
	// (unless skipped) a throwaway GPU probe LXC. See #681.
	ProfileBackend(context.Context, *ProfileBackendRequest) (*ProfileBackendResponse, error)
	// GetCapabilityProfile reads a backend's last-recorded capability profile
	// without re-running the benchmark/probe. Admin-only. See #681.
	GetCapabilityProfile(context.Context, *GetCapabilityProfileRequest) (*GetCapabilityProfileResponse, error)
	// GetSelfMeasurement computes and signs a fresh integrity self-measurement
	// for a backend: digests of the running daemon binary, the loaded in-kernel
	// network-policy program object(s), and the canonical policy/config state,
	// signed with the node's identity key (the sentinel-issued peer leaf reused
	// from the peer-PKI plumbing; TPM-backed when present). The daemon also emits
	// this on its heartbeat; this RPC exposes the same measurement on demand. The
	// control plane verifies it to detect tampering. Admin-only. See #683.
	GetSelfMeasurement(context.Context, *GetSelfMeasurementRequest) (*GetSelfMeasurementResponse, error)
	// GetLatestRelease reports the latest Containarium release on GitHub vs the
	// running version, so operators see "update available" without SSHing in.
	// The GitHub lookup is cached server-side (1h) to spare the rate limit. #354.
	GetLatestRelease(context.Context, *GetLatestReleaseRequest) (*GetLatestReleaseResponse, error)
	// ValidateGPU proves GPU passthrough works from inside an LXC on a backend:
	// the daemon launches a throwaway nvidia.runtime LXC, runs nvidia-smi inside,
	// tears it down, and returns the parsed model + driver. Admin-only; the check
	// creates and deletes a short-lived container. See #316.
	ValidateGPU(context.Context, *ValidateGPURequest) (*ValidateGPUResponse, error)
	// TriggerUpgrade upgrades a backend's daemon now rather than waiting for the
	// periodic auto-update tick: the daemon pulls the binary the sentinel
	// currently serves (SHA-verified), smoke-tests it, swaps atomically (keeping
	// .old), and restarts. Admin-only. Async — poll GetUpgradeStatus or watch the
	// version in ListBackends. backend_id in the body, empty = local. #354 Phase B.
	TriggerUpgrade(context.Context, *TriggerUpgradeRequest) (*TriggerUpgradeResponse, error)
	// GetUpgradeStatus polls an upgrade started by TriggerUpgrade. A local
	// self-upgrade restarts the daemon and loses in-memory job state, so after a
	// restart this returns "unknown" — compare the backend version in
	// ListBackends instead. #354.
	GetUpgradeStatus(context.Context, *GetUpgradeStatusRequest) (*GetUpgradeStatusResponse, error)
	// GetMonitoringInfo gets monitoring configuration (Grafana/VictoriaMetrics URLs)
	GetMonitoringInfo(context.Context, *GetMonitoringInfoRequest) (*GetMonitoringInfoResponse, error)
	// SetMetricsExport enables or disables opt-in export of host/container
	// infra metrics to the host cloud's native monitoring (GCP Cloud
	// Monitoring in the MVP; AWS is a reserved enum value that returns
	// UNIMPLEMENTED). Enabling validates the provider and, for GCP, resolves
	// Application Default Credentials with the monitoring-write scope as a
	// synchronous dry run — a host with no usable ADC gets FAILED_PRECONDITION
	// with an IAM remediation hint and nothing is persisted or started.
	// Disabling stops emission within one export interval. Neither direction
	// requires a daemon restart. #1069 delivers the toggle, config
	// persistence, and the credential probe; the metrics collector itself
	// lands with #1070/#1071.
	SetMetricsExport(context.Context, *SetMetricsExportRequest) (*SetMetricsExportResponse, error)
	// GetMetricsExport returns the current cloud-native metrics export
	// configuration and last-known health (last success time, last error,
	// failure count — populated once #1070/#1071 wire the collector).
	GetMetricsExport(context.Context, *GetMetricsExportRequest) (*GetMetricsExportResponse, error)
	// CreateAlertRule creates a new custom alert rule
	CreateAlertRule(context.Context, *CreateAlertRuleRequest) (*CreateAlertRuleResponse, error)
	// ListAlertRules lists all alert rules
	ListAlertRules(context.Context, *ListAlertRulesRequest) (*ListAlertRulesResponse, error)
	// GetAlertRule gets a single alert rule by ID
	GetAlertRule(context.Context, *GetAlertRuleRequest) (*GetAlertRuleResponse, error)
	// UpdateAlertRule updates an existing alert rule
	UpdateAlertRule(context.Context, *UpdateAlertRuleRequest) (*UpdateAlertRuleResponse, error)
	// DeleteAlertRule deletes an alert rule
	DeleteAlertRule(context.Context, *DeleteAlertRuleRequest) (*DeleteAlertRuleResponse, error)
	// GetAlertingInfo gets alerting system status and configuration
	GetAlertingInfo(context.Context, *GetAlertingInfoRequest) (*GetAlertingInfoResponse, error)
	// ListDefaultAlertRules lists the built-in default alert rules
	ListDefaultAlertRules(context.Context, *ListDefaultAlertRulesRequest) (*ListDefaultAlertRulesResponse, error)
	// UpdateAlertingConfig updates alerting system configuration (webhook URL)
	UpdateAlertingConfig(context.Context, *UpdateAlertingConfigRequest) (*UpdateAlertingConfigResponse, error)
	// TestWebhook sends a test notification to the configured webhook with current system status
	TestWebhook(context.Context, *TestWebhookRequest) (*TestWebhookResponse, error)
	// ListWebhookDeliveries lists webhook delivery history
	ListWebhookDeliveries(context.Context, *ListWebhookDeliveriesRequest) (*ListWebhookDeliveriesResponse, error)
	// SetSecret creates or updates a tenant secret. Idempotent —
	// repeated calls with the same (username, name) bump the version
	// and replace the value. See docs/SECRETS-MANAGEMENT-DESIGN.md.
	SetSecret(context.Context, *SetSecretRequest) (*SetSecretResponse, error)
	// GetSecret reads a single secret's plaintext value. Always
	// audit-logged. Admin JWT required (v1).
	GetSecret(context.Context, *GetSecretRequest) (*GetSecretResponse, error)
	// ListSecrets enumerates a tenant's secrets, metadata only —
	// names + versions + timestamps. Never returns values.
	ListSecrets(context.Context, *ListSecretsRequest) (*ListSecretsResponse, error)
	// DeleteSecret removes a secret. Does not auto-clean env-var
	// stamps on running containers — caller invokes RefreshSecrets
	// separately if needed.
	DeleteSecret(context.Context, *DeleteSecretRequest) (*DeleteSecretResponse, error)
	// RefreshSecrets re-stamps the LXC's environment.<NAME> config
	// keys from the current secret-store state for the tenant.
	// Running processes don't pick up the new env (POSIX semantics);
	// useful after rotation when the next exec'd process should see
	// the new value without a full container restart.
	RefreshSecrets(context.Context, *RefreshSecretsRequest) (*RefreshSecretsResponse, error)
	mustEmbedUnimplementedContainerServiceServer()
}

